package com.example.hybridwebview;

import android.os.Bundle;
import android.webkit.WebView;

import androidx.activity.OnBackPressedCallback;
import androidx.annotation.Nullable;
import androidx.appcompat.app.AppCompatActivity;

public class HybridWebViewActivity extends AppCompatActivity {

    private WebView webView;
    private HybridWebViewManager hybridWebViewManager;

    @Override
    protected void onCreate(@Nullable Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);

        webView = new WebView(this);
        setContentView(webView);

        hybridWebViewManager = new HybridWebViewManager(
                this,
                webView,
                "https://your-mobile-website.example.com",
                (payloadJson, callback) -> {
                    callback.onSuccess("{\"status\":\"paid\",\"transactionId\":\"demo_txn_123\"}");
                }
        );
        hybridWebViewManager.initialize();

        getOnBackPressedDispatcher().addCallback(this, new OnBackPressedCallback(true) {
            @Override
            public void handleOnBackPressed() {
                if (hybridWebViewManager.canGoBack()) {
                    hybridWebViewManager.goBack();
                } else {
                    finish();
                }
            }
        });
    }

    @Override
    protected void onResume() {
        super.onResume();
        hybridWebViewManager.onResume();
    }

    @Override
    protected void onPause() {
        hybridWebViewManager.onPause();
        super.onPause();
    }

    @Override
    protected void onDestroy() {
        hybridWebViewManager.destroy();
        super.onDestroy();
    }
}